import type { CashVoucherDto } from '../../services/kt/models';

/**
 * Số phiếu tối đa trong cache next/prev.
 * - Slideout Tìm: PAGE_SIZE = 20 (một trang) — thực tế ≤ 20
 * - Cap 50: tránh phình `location.state` / memory; không gom nhiều trang list
 * - Catalog list ERP thường 50/100/200 — 50 đủ cho voucher browse
 */
export const VOUCHER_SEARCH_CACHE_MAX = 50;

/** React Router `location.state` key — copy chứng từ → `/them`. */
export const VOUCHER_COPY_STATE_KEY = 'voucherCopySnapshot';

/** React Router `location.state` key — số CT nguồn khi Copy → hint toolbar. */
export const VOUCHER_COPY_SOURCE_CODE_KEY = 'voucherCopySourceCode';

/** React Router `location.state` key — danh sách id sau Tìm kiếm (next/prev). */
export const VOUCHER_SEARCH_RESULT_IDS_KEY = 'voucherSearchResultIds';

/** Trang kết quả tìm — `CashVoucherDto[]` để next/prev không GET lại DB. */
export const VOUCHER_SEARCH_CACHE_KEY = 'voucherSearchCache';

/** Cắt cache — tối đa `VOUCHER_SEARCH_CACHE_MAX` phiếu (1 trang kết quả). */
export function normalizeVoucherSearchCache(
  items: CashVoucherDto[] | undefined,
): CashVoucherDto[] {
  if (!items?.length) return [];
  return items.slice(0, VOUCHER_SEARCH_CACHE_MAX);
}

export function buildVoucherSearchNavigateState(
  ids: string[],
  items?: CashVoucherDto[],
): Record<string, string[] | CashVoucherDto[]> {
  const limitedIds = ids.slice(0, VOUCHER_SEARCH_CACHE_MAX);
  const state: Record<string, string[] | CashVoucherDto[]> = {
    [VOUCHER_SEARCH_RESULT_IDS_KEY]: limitedIds,
  };
  const cached = normalizeVoucherSearchCache(items);
  if (cached.length) state[VOUCHER_SEARCH_CACHE_KEY] = cached;
  return state;
}

export function voucherSearchCacheToMap(
  items: CashVoucherDto[] | undefined,
): Map<string, CashVoucherDto> {
  const limited = normalizeVoucherSearchCache(items);
  if (!limited.length) return new Map();
  return new Map(limited.map(v => [v.id, v]));
}
